        Vector3 w = bounds.getExtents();
        nx = (int) Math.max(((w.x / gatherRadius) + 0.5f), 1);
        ny = (int) Math.max(((w.y / gatherRadius) + 0.5f), 1);
        nz = (int) Math.max(((w.z / gatherRadius) + 0.5f), 1);
